    def user_root(self, user_id: str) -> Path:
        root = self.codes_root / user_id
        root.mkdir(parents=True, exist_ok=True)
        return root

    def scheduler_limits_enabled(self) -> bool:
        return bool(self.max_user > 0 or self.max_user_sessions > 0)

    def task_queue_size(self) -> int:
        with self._lock:
            return int(len(self._task_queue))

    def _running_counts_locked(self) -> tuple[int, dict[str, int]]:
        total = 0
        per_user: dict[str, int] = {}
        for uid, mgr in list(self._session_mgrs.items()):
            try:
                with mgr.lock:
                    sessions = list(mgr.sessions.values())
            except Exception:
                sessions = []
            running = 0
            for sess in sessions:
                try:
                    if bool(getattr(sess, "running", False)):
                        running += 1
                except Exception:
                    continue
            if running > 0:
                per_user[uid] = running
                total += running
        return int(total), per_user

    def _can_start_for_user_locked(self, user_id: str) -> tuple[bool, str, int, dict[str, int]]:
        total_running, per_user = self._running_counts_locked()
        if self.max_user > 0 and total_running >= self.max_user:
            return False, "max_user", int(total_running), per_user
        user_running = int(per_user.get(str(user_id or ""), 0))
        if self.max_user_sessions > 0 and user_running >= self.max_user_sessions:
            return False, "max_user_sessions", int(total_running), per_user
        return True, "", int(total_running), per_user

    def _emit_scheduler_started(self, rows: list[dict]):
        for row in rows:
            req = row.get("request", {}) if isinstance(row, dict) else {}
            sess = row.get("session")
            if not isinstance(sess, SessionState):
                continue
            wait_sec = max(0.0, now_ts() - float(req.get("queued_at", 0.0) or 0.0))
            try:
                sess._emit(
                    "status",
                    {
                        "summary": (
                            "scheduler started queued task "
                            f"#{int(req.get('id', 0) or 0)} after {wait_sec:.1f}s"
                        )
                    },
                )
            except Exception:
                continue

    def _drain_task_queue_locked(self) -> list[dict]:
        started: list[dict] = []
        if not self.scheduler_limits_enabled():
            return started
        while self._task_queue:
            req = self._task_queue[0] if self._task_queue else {}
            uid = str(req.get("user_id", "") or "")
            sid = str(req.get("session_id", "") or "")
            mgr = self._session_mgrs.get(uid)
            if not mgr:
                self._task_queue.popleft()
                continue
            sess = mgr.get(sid)
            if not sess:
                self._task_queue.popleft()
                continue
            if bool(getattr(sess, "running", False)):
                break
            ok, _, _, _ = self._can_start_for_user_locked(uid)
            if not ok:
                break
            self._task_queue.popleft()
            try:
                out = sess.submit_user_message(str(req.get("content", "") or ""))
            except Exception as exc:
                out = {"ok": False, "error": str(exc)}
            started.append({"request": req, "result": out, "session": sess})
        return started

    def _on_session_run_finished(self, user_id: str, session_id: str):
        if not self.scheduler_limits_enabled():
            return
        started_rows: list[dict] = []
        with self._lock:
            started_rows = self._drain_task_queue_locked()
        if started_rows:
            self._emit_scheduler_started(started_rows)

    def scheduler_status(self, user_id: str = "") -> dict:
        with self._lock:
            total_running, per_user = self._running_counts_locked()
            queue_size = int(len(self._task_queue))
            user_id_norm = str(user_id or "")
            queued_for_user = sum(1 for row in self._task_queue if str(row.get("user_id", "")) == user_id_norm)
            return {
                "enabled": bool(self.scheduler_limits_enabled()),
                "max_user": int(self.max_user),
                "max_user_sessions": int(self.max_user_sessions),
                "running_total": int(total_running),
                "running_user": int(per_user.get(user_id_norm, 0)),
                "queue_size": queue_size,
                "queued_user": int(queued_for_user),
            }

    def submit_user_message(self, user_id: str, session_id: str, content: str) -> dict:
        mgr = self.manager_for_user(user_id)
        sess = mgr.get(session_id)
        if not sess:
            raise KeyError(session_id)
        text = str(content or "").strip()
        if not text:
            raise ValueError("content required")
        if not self.scheduler_limits_enabled():
            return sess.submit_user_message(text)

        started_rows: list[dict] = []
        response: dict = {"ok": True, "queued": True}
        queue_id = 0
        with self._lock:
            self._task_queue_seq = int(self._task_queue_seq) + 1
            queue_id = int(self._task_queue_seq)
            req = {
                "id": queue_id,
                "user_id": str(user_id or ""),
                "session_id": str(session_id or ""),
                "content": text,
                "queued_at": now_ts(),
            }
            self._task_queue.append(req)
            started_rows = self._drain_task_queue_locked()
            started_self = None
            for row in started_rows:
                row_req = row.get("request", {}) if isinstance(row, dict) else {}
                if int(row_req.get("id", 0) or 0) == queue_id:
                    started_self = row
                    break
            if started_self is not None:
                out = started_self.get("result")
                if isinstance(out, dict):
                    response = dict(out)
                else:
                    response = {"ok": True, "result": out}
                response.setdefault("ok", True)
                response["queued"] = bool(response.get("queued", False))
                response["running"] = bool(response.get("running", True))
                response["scheduler_started"] = True
                response["queue_id"] = queue_id
                response["queue_position"] = 0
                response["limits"] = {
                    "max_user": int(self.max_user),
                    "max_user_sessions": int(self.max_user_sessions),
                }
            else:
                queue_position = 1
                for idx, row in enumerate(self._task_queue):
                    if int(row.get("id", 0) or 0) == queue_id:
                        queue_position = idx + 1
                        break
                _, reason, total_running, per_user = self._can_start_for_user_locked(str(user_id or ""))
                scheduler_reason = reason or ("session_running_requeue" if bool(getattr(sess, "running", False)) else "fifo_wait")
                response = {
                    "ok": True,
                    "queued": True,
                    "running": False,
                    "queue_id": queue_id,
                    "queue_position": int(queue_position),
                    "queue_size": int(len(self._task_queue)),
                    "scheduler_reason": scheduler_reason,
                    "limits": {
                        "max_user": int(self.max_user),
                        "max_user_sessions": int(self.max_user_sessions),
                        "running_total": int(total_running),
                        "running_user": int(per_user.get(str(user_id or ""), 0)),
                    },
                }
        if started_rows:
            self._emit_scheduler_started(started_rows)
        if bool(response.get("queued")) and not bool(response.get("scheduler_started")):
            try:
                sess._emit(
                    "status",
                    {
                        "summary": (
                            "scheduler queued task "
                            f"#{queue_id} (position={int(response.get('queue_position', 1) or 1)})"
                        )
                    },
                )
            except Exception:
                pass
        return response

    def manager_for_user(self, user_id: str) -> SessionManager:
        with self._lock:
            if user_id in self._session_mgrs:
                return self._session_mgrs[user_id]
            root = self.user_root(user_id) / "sessions"
            root.mkdir(parents=True, exist_ok=True)
            mgr = SessionManager(
                root,
                user_id,
                self.base_url,
                self.model,
                self.skills_root,
                self.js_lib_root,
                self.crypto,
                REPO_ROOT,
                self.thinking,
                self.default_llm_config,
                self.default_language,
                self.context_token_limit,
                self.context_limit_locked,
                self.max_rounds,
                self.max_run_seconds,
                self.auto_model_switch,
                self.arbiter_enabled,
                self.arbiter_model,
                self.arbiter_timeout_seconds,
                self.arbiter_max_tokens,
                self.arbiter_temperature,
                self.execution_mode,
                self.max_output_tokens,
                upload_callback=self._on_session_upload,
                run_finished_callback=self._on_session_run_finished,
                reference_prepare_callback=self._prepare_runtime_references,
                query_code_library_callback=self._query_code_library_tool,
                query_knowledge_library_callback=self._query_knowledge_library_tool,
                code_library_root=self.code_root,
                code_library_status_callback=self._code_library_status_for_session,
                knowledge_library_root=self.rag_root,
                knowledge_library_status_callback=self._knowledge_library_status_for_session,
            )
            self._session_mgrs[user_id] = mgr
            return mgr

    def _known_user_ids(self) -> list[str]:
        ids: set[str] = set()
        try:
            for path in sorted(self.codes_root.glob("user_*")):
                if path.is_dir():
                    ids.add(path.name)
        except Exception:
            pass
        with self._lock:
            ids.update(self._session_mgrs.keys())
        return sorted(ids)

    def persist_all_sessions(self, include_running: bool = True, lock_timeout: float = 0.8) -> dict:
        out = {
            "checked_users": 0,
            "total_sessions": 0,
            "persisted": 0,
            "busy": 0,
            "skipped_running": 0,
            "errors": [],
            "ts": now_ts(),
        }
        timeout = max(0.0, float(lock_timeout or 0.0))
        with self._lock:
            managers = list(self._session_mgrs.items())
        out["checked_users"] = len(managers)
        for uid, mgr in managers:
            try:
                with mgr.lock:
                    sessions = list(mgr.sessions.values())
            except Exception as exc:
                out["errors"].append(f"{uid}:manager_snapshot_failed:{trim(str(exc), 220)}")
                continue
            for sess in sessions:
                out["total_sessions"] += 1
                if (not include_running) and bool(getattr(sess, "running", False)):
                    out["skipped_running"] += 1
                    continue
                acquired = False
                try:
                    acquired = bool(sess.lock.acquire(timeout=timeout))
                except Exception:
                    acquired = False
                if not acquired:
                    out["busy"] += 1
                    continue
                try:
                    sess.updated_at = now_ts()
                    sess._persist()
                    out["persisted"] += 1
                except Exception as exc:
                    out["errors"].append(
                        f"{uid}/{getattr(sess, 'id', '?')}:persist_failed:{trim(str(exc), 220)}"
                    )
                finally:
                    try:
                        sess.lock.release()
                    except Exception:
                        pass
        out["error_count"] = len(out["errors"])
        return out

    def apply_global_llm_config(self, config: dict, source: str = "") -> dict:
        cfg = dict(config or {})
        OllamaClient.clear_global_probe_cache()
        parsed = parse_llm_config_profiles(cfg, self.base_url, self.model)
        self.default_llm_config = cfg
        self.global_profiles_payload = parsed
        self.global_profiles = {str(p.get("id")): dict(p) for p in parsed.get("profiles", [])}
        self.global_active_profile_id = str(
            parsed.get("default_profile_id")
            or (next(iter(self.global_profiles.keys())) if self.global_profiles else "ollama")
        )
        active = dict(self.global_profiles.get(self.global_active_profile_id, {}))
        self._sync_global_ollama_defaults(active)
        self.thinking = False
        cfg_max_output_tokens = cfg.get("max_output_tokens")
        if cfg_max_output_tokens is not None:
            self.max_output_tokens = max(256, int(cfg_max_output_tokens))
        if "single_advance_prompt_enhance" in cfg:
            self.single_advance_prompt_enhance = bool(cfg["single_advance_prompt_enhance"])

        def normalized_profiles() -> tuple[dict[str, dict], str]:
            rows: dict[str, dict] = {}
            for idx, profile in enumerate(parsed.get("profiles", [])):
                pid = sanitize_profile_id(str(profile.get("id") or f"profile-{idx+1}"))
                if pid in rows:
                    n = 2
                    while f"{pid}-{n}" in rows:
                        n += 1
                    pid = f"{pid}-{n}"
                item = dict(profile)
                item["id"] = pid
                item["selection"] = f"{pid}::{item.get('model','')}"
                if source:
                    item["source"] = source
                rows[pid] = item
            if not rows:
                rows["ollama"] = {
                    "id": "ollama",
                    "provider": "ollama",
                    "label": "Ollama",
                    "model": self.model,
                    "base_url": self.base_url,
                    "temperature": 0.2,
                    "request_timeout": DEFAULT_REQUEST_TIMEOUT,
                    "selection": f"ollama::{self.model}",
                    "capabilities": infer_model_multimodal_capabilities("ollama", self.model),
                    "media_endpoints": {},
                    "source": source or "fallback",
                }
            requested = sanitize_profile_id(str(parsed.get("default_profile_id", "")))
            active_id = requested if requested in rows else next(iter(rows.keys()))
            return rows, active_id

        profiles_map, active_id = normalized_profiles()

        persisted_path = ""
        persisted_error = ""
        try:
            LLM_CONFIG_PATH.write_text(json_dumps(cfg, indent=2), encoding="utf-8")
            persisted_path = str(LLM_CONFIG_PATH)
        except Exception as exc:
            persisted_error = str(exc)

        updated_users = 0
        updated_sessions = 0
        live_users = 0
        live_sessions = 0
        disk_users = 0
        disk_sessions = 0
        errors: list[str] = []

        with self._lock:
            live_mgrs = list(self._session_mgrs.items())
        for uid, mgr in live_mgrs:
            try:
                mgr.reset_to_llm_config(cfg, source=source or "global-config")
                live_users += 1
                live_sessions += len(mgr.sessions)
            except Exception as exc:
                errors.append(f"{uid}: {exc}")

        live_user_ids = {uid for uid, _ in live_mgrs}
        for user_dir in sorted(self.codes_root.glob("user_*")):
            if not user_dir.is_dir():
                continue
            uid = user_dir.name
            if uid in live_user_ids:
                continue
            try:
                user_prefs_path = user_dir / "user_prefs.json"
                ui_lang = self.default_language
                if user_prefs_path.exists():
                    raw = self.crypto.read_json(user_prefs_path, {})
                    ui_lang = normalize_ui_language(raw.get("ui_language", ui_lang))
                active_profile = dict(profiles_map.get(active_id, {}))
                ollama_profile = {}
                if str(active_profile.get("provider", "")).lower() == "ollama":
                    ollama_profile = dict(active_profile)
                else:
                    for prow in profiles_map.values():
                        if str(prow.get("provider", "")).lower() == "ollama":
                            ollama_profile = dict(prow)
                            break
                model_text = str(ollama_profile.get("model", self.model) or self.model)
                base_text = str(ollama_profile.get("base_url", self.base_url) or self.base_url)
                user_prefs_payload = {
                    "model_profiles": profiles_map,
                    "active_profile_id": active_id,
                    "model": model_text,
                    "ollama_base": base_text,
                    "thinking": False,
                    "ui_language": ui_lang,
                    "updated_at": now_ts(),
                }
                self.crypto.write_json(user_prefs_path, user_prefs_payload)
                disk_users += 1

                sessions_root = user_dir / "sessions"
                if sessions_root.exists() and sessions_root.is_dir():
                    for state_file in sorted(sessions_root.glob("*/state.json")):
                        if not state_file.exists() or not state_file.is_file():
                            continue
                        try:
                            sraw = self.crypto.read_json(state_file, {})
                            sraw["model_profiles"] = profiles_map
                            sraw["active_profile_id"] = active_id
                            sraw["multimodal_capability_cache"] = {}
                            sraw["updated_at"] = now_ts()
                            self.crypto.write_json(state_file, sraw)
                            disk_sessions += 1
                        except Exception as exc:
                            errors.append(f"{uid}:{state_file.name}: {exc}")
            except Exception as exc:
                errors.append(f"{uid}: {exc}")

        updated_users = live_users + disk_users
        updated_sessions = live_sessions + disk_sessions

        out = {
            "ok": not errors,
            "source": source,
            "profiles": len(parsed.get("profiles", [])),
            "default_profile_id": self.global_active_profile_id,
            "updated_users": updated_users,
            "updated_sessions": updated_sessions,
            "live_users_updated": live_users,
            "disk_users_updated": disk_users,
            "live_sessions_updated": live_sessions,
            "disk_sessions_updated": disk_sessions,
            "persisted_path": persisted_path,
        }
        if persisted_error:
            out["persist_warning"] = persisted_error
        if errors:
            out["errors"] = errors[:20]
        return out

